import{_ as n,o as t,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"69I. Prevention Of Gendered Violence Including Sexual Harassment","description":"","frontmatter":{"title":"69I. Prevention Of Gendered Violence Including Sexual Harassment","eba":"Mental Health Services 2024-2028","topics":["ohs","gendered-violence"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69I-prevention-of-gendered-violence-including-sexual-harassment.md","filePath":"ebas/mental-health/common-terms/ohs/69I-prevention-of-gendered-violence-including-sexual-harassment.md"}'),a={name:"ebas/mental-health/common-terms/ohs/69I-prevention-of-gendered-violence-including-sexual-harassment.md"};function r(i,e,l,p,c,d){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_69i-prevention-of-gendered-violence-including-sexual-harassment" tabindex="-1">69I. Prevention Of Gendered Violence Including Sexual Harassment <a class="header-anchor" href="#_69i-prevention-of-gendered-violence-including-sexual-harassment" aria-label="Permalink to &quot;69I. Prevention Of Gendered Violence Including Sexual Harassment&quot;">​</a></h1><p><strong>69I.1</strong> Duties</p><p><strong>(a)</strong> Employers, employees and others have specific duties relating to work-related gendered violence (including work-related sexual harassment) under the OHS Act and the EO Act.</p><p><strong>(b)</strong> Employers have a positive duty to eliminate, as far as possible, sexual harassment in connection with work, which is unlawful.</p><p><strong>69I.2</strong> Definitions</p><p><strong>(a)</strong> Work-related gendered violence</p><p>Work-related gendered violence is any behaviour, directed at any person, or that affects a person, because of their sex, gender or sexual orientation, or because they do not adhere to socially prescribed gender roles, that creates a risk to health and safety.</p><p><strong>(b)</strong> Sexual harassment</p><p><strong>(i)</strong> A person sexually harasses another person if they:</p><p><strong>(A)</strong> make an unwelcome sexual advance, or an unwelcome request for sexual favours, to the other person, or</p><p><strong>(B)</strong> engage in any other unwelcome conduct of a sexual nature in relation to the other person,</p><p>in circumstances in which a reasonable person, having regard to all the circumstances, would have anticipated that the other person would be offended, humiliated or intimidated. The motive or intention of the person engaging in sexual harassment is irrelevant.</p><p><strong>(ii)</strong> A person can be a victim of sexual harassment if they witnessed, overheard or were in the presence of unwelcome conduct of a sexual nature, even if the conduct was not directed at them.</p><p><strong>(iii)</strong> A person may be taken to have engaged in sexual harassment if they cause, instruct, induce, aid or permit another person to engage in sexual harassment, even if they did not directly carry out the sexual harassment themselves.</p><p><strong>(c)</strong> Examples of work-related sexual harassment Work-related sexual harassment is sexual harassment (as described above) directed at a person, that can happen at work, work related events, or between people sharing the same workplace. Work-related sexual harassment isn’t always obvious, repeated or continuous. Work related evets include external meetings or conferences, training courses or workshops, social gatherings (e.g. team lunches), etc.</p><p>It can be a one-off incident and can involve unwanted or unwelcome:</p><p><strong>(i)</strong> touching</p><p><strong>(ii)</strong> staring or leering</p><p><strong>(iii)</strong> following or watching inappropriately, or loitering inappropriately, either in person or digitally</p><p><strong>(iv)</strong> sexually suggestive comments, jokes, or nicknames</p><p><strong>(v)</strong> sexually explicit pictures or posters</p><p><strong>(vi)</strong> repeated invitations to go out on dates</p><p><strong>(vii)</strong> requests for sex</p><p><strong>(viii)</strong> intrusive questions about a person&#39;s private life or body</p><p><strong>(ix)</strong> unnecessary contact, such as deliberately brushing up against a person</p><p><strong>(x)</strong> insults or taunts based on sex or gender</p><p><strong>(xi)</strong> sexually explicit physical contact; or</p><p><strong>(xii)</strong> sexually explicit emails, text messages or social media activity.</p><p><strong>69I.3</strong> Polices</p><p><strong>(a)</strong> Maintenance of policies</p><p>Each Employer will:</p><p><strong>(i)</strong> maintain policies regarding work-related gendered violence including sexual harassment</p><p><strong>(ii)</strong> Ensure those policies are accessible to employees</p><p><strong>(iii)</strong> Provide training to Employees regarding the content of those policies; and</p><p><strong>(iv)</strong> Support a culture of reporting of incidents.</p><p>A copy of these polices is available to a Union on request.</p><p><strong>(b)</strong> Standard of Policies</p><p>Each policy will define work-related gendered violence and sexual harassment and identify:</p><p><strong>(i)</strong> how and to whom complaints can be made</p><p><strong>(ii)</strong> the supports available to affected employees</p><p><strong>(iii)</strong> The steps taken it identify risk, assess that risk, and as far as is practicable eliminate that risk. Where the risk cannot be practicably eliminated, then the policy will describe the controls in place to minimise that risk; and</p><p><strong>(iv)</strong> The steps that will be taken to address the complaint including investigation, outcome and, where appropriate, contact with external agencies such as Victoria Police.</p><p><strong>(c)</strong> Resources</p><p>Resources that should be considered in reviewing or developing work related gendered violence and sexual harassment policies include:</p><p><strong>(i)</strong> WorkSafe’s Work-related gendered violence including sexual harassment resources; and</p><p><strong>(ii)</strong> Victorian Public Sector Commission’s Model Sexual Harassment Policy and Practice Guide.</p><p><strong>69I.4</strong> Workplace Implementation Committee</p><p>The Employer’s policies regarding work-related gendered violence and sexual harassment will be provided to the Workplace Implementation Committee for the purpose of discussion and feedback.</p><p>AND MENTAL HEALTH OFFICERS</p><p>Plain language terms: sexual harassment, harassment, sexist behaviour, sexism.</p>',50)])])}const u=n(a,[["render",r]]);export{h as __pageData,u as default};
